const fs=require('fs');
const path='index.html';
let s=fs.readFileSync(path,'utf8');

const oldTarget='<div class="targetBox"><label>Target / Line</label><input class="target"></div>';
const newTarget='<div class="targetBox"><label>Target / Line</label><select class="targetSelect"><option value="">Select target…</option></select><input class="target targetCustom manualInput hide" inputmode="decimal" placeholder="Custom line"></div>';
if(!s.includes(oldTarget)) throw new Error('target markup not found');
s=s.replace(oldTarget,newTarget);

const oldBind='div.querySelector(".target").addEventListener("input",()=>{autoFillLabel(div);preview()});div.querySelector(".half")';
const newBind='div.querySelector(".targetSelect").addEventListener("change",()=>{showManual(div.querySelector(".targetSelect"),div.querySelector(".targetCustom"));autoFillLabel(div);preview()});div.querySelector(".target").addEventListener("input",()=>{autoFillLabel(div);preview()});div.querySelector(".half")';
if(!s.includes(oldBind)) throw new Error('target listener not found');
s=s.replace(oldBind,newBind);

const insertAfter='function renderOptions(sel,items,placeholder,allowManual){let old=sel.value;sel.innerHTML=opt("",placeholder||"Select…")+(items||[]).map(x=>typeof x==="string"?opt(x):opt(x.value,x.label||x.value)).join("")+(allowManual?opt(MAN,"Manual entry…"):"");if(old&&[...sel.options].some(o=>o.value===old))sel.value=old}\n';
if(!s.includes(insertAfter)) throw new Error('renderOptions anchor not found');
const targetLogic=`function numRange(min,max,step=1){let out=[];for(let n=min;n<=max+1e-9;n+=step)out.push(Number(n.toFixed(2)));return out}\nfunction targetSpec(t,l){\n  const milestone={\n    player_hits:numRange(1,5),player_total_bases:numRange(1,8),player_runs:numRange(1,4),player_hr:numRange(1,3),player_rbi:numRange(1,5),player_walks:numRange(1,4),player_stolen_bases:numRange(1,3),player_hwsb:numRange(1,8),player_hrrbi:numRange(1,10),pitcher_ks:numRange(1,15),\n    player_points:numRange(5,50),player_rebounds:numRange(1,25),player_assists:numRange(1,20),player_points_rebounds:numRange(5,70),player_pr:numRange(5,70),player_points_assists:numRange(5,70),player_pa:numRange(5,70),player_rebounds_assists:numRange(2,40),player_ra:numRange(2,40),player_points_rebounds_assists:numRange(10,90),player_pra:numRange(10,90),player_blocks:numRange(1,10),player_threes:numRange(1,12),\n    player_goal:numRange(1,3),player_goal_et:numRange(1,3),player_assist:numRange(1,3),player_goal_or_assist:numRange(1,4),player_shots:numRange(1,10),player_sot:numRange(1,7),player_fouls:numRange(1,8),player_fouls_drawn:numRange(1,8),player_tackles:numRange(1,10),player_cards:numRange(1,3)\n  };\n  if(milestone[t])return{mode:'milestone',values:milestone[t]};\n  if(t==='pitcher_ks_under')return{mode:'line',values:numRange(.5,15.5,1)};\n  if(t==='pitcher_outs_under')return{mode:'line',values:numRange(.5,26.5,1)};\n  if(['spread','f5_spread','h1_spread'].includes(t)){let max=l==='MLB'?6.5:l==='WC'?5.5:30.5;return{mode:'spread',values:numRange(-max,max,1).filter(n=>n!==0)}}\n  if(['f5_total_over','f5_total_under'].includes(t))return{mode:'line',values:numRange(.5,12.5,1)};\n  if(['total_over','total_under'].includes(t)){let max=l==='MLB'?20.5:l==='NBA'||l==='WNBA'?300.5:8.5;return{mode:'line',values:numRange(.5,max,1)}}\n  if(['team_total_over','team_total_under'].includes(t)){let max=l==='MLB'?12.5:l==='NBA'||l==='WNBA'?180.5:6.5;return{mode:'line',values:numRange(.5,max,1)}}\n  if(['h1_total_over','h1_total_under','h2_total_over','h2_total_under'].includes(t))return{mode:'line',values:numRange(.5,6.5,1)};\n  if(['team_corners_over','team_corners_under'].includes(t))return{mode:'line',values:numRange(.5,12.5,1)};\n  if(['match_corners_over','match_corners_under'].includes(t))return{mode:'line',values:numRange(.5,20.5,1)};\n  if(['team_cards_over','team_cards_under'].includes(t))return{mode:'line',values:numRange(.5,7.5,1)};\n  if(['match_cards_over','match_cards_under'].includes(t))return{mode:'line',values:numRange(.5,12.5,1)};\n  if(['team_shots_over','team_shots_under'].includes(t))return{mode:'line',values:numRange(.5,30.5,1)};\n  if(['match_shots_over','match_shots_under'].includes(t))return{mode:'line',values:numRange(.5,50.5,1)};\n  if(['team_sot_over','team_sot_under','team_sot_half_over','team_sot_half_under'].includes(t))return{mode:'line',values:numRange(.5,15.5,1)};\n  if(['match_sot_over','match_sot_under'].includes(t))return{mode:'line',values:numRange(.5,25.5,1)};\n  return{mode:'none',values:[]};\n}\nfunction targetText(v,mode){if(mode==='milestone')return v+'+';if(mode==='spread'&&Number(v)>0)return'+'+v;return String(v)}\nfunction targetValue(d){let sel=d.querySelector('.targetSelect'),custom=d.querySelector('.targetCustom');if(!sel)return clean(custom?.value);return sel.value===MAN?clean(custom.value):clean(sel.value)}\nfunction configureTarget(d){let t=d.querySelector('.ltype').value,l=legLeague(d),sel=d.querySelector('.targetSelect'),custom=d.querySelector('.targetCustom'),current=targetValue(d),spec=targetSpec(t,l);if(spec.mode==='none'){sel.innerHTML=opt('','No target required');sel.value='';custom.value='';custom.classList.add('hide');return}sel.innerHTML=opt('','Select target…')+spec.values.map(v=>opt(v,targetText(v,spec.mode))).join('')+opt(MAN,'Custom line…');let match=[...sel.options].some(o=>o.value===String(current));if(current&&match){sel.value=String(current);custom.classList.add('hide')}else if(current){sel.value=MAN;custom.value=current;custom.classList.remove('hide')}else{sel.value='';custom.value='';custom.classList.add('hide')}}\n`;
s=s.replace(insertAfter,insertAfter+targetLogic);

const oldRefresh='d.querySelector(".targetBox").classList.toggle("hide",!needsTarget(t));d.querySelector(".halfBox")';
const newRefresh='d.querySelector(".targetBox").classList.toggle("hide",!needsTarget(t));configureTarget(d);d.querySelector(".halfBox")';
if(!s.includes(oldRefresh)) throw new Error('refresh target anchor not found');
s=s.replace(oldRefresh,newRefresh);

s=s.replaceAll('clean(d.querySelector(".target").value)','targetValue(d)');

fs.writeFileSync(path,s);
